func computeScore(values: int[], weights: int[], offset: int): int {
    val score = 0
    val i = 0
    while (i < values.length && i < weights.length) {
        val contrib = values[i] * weights[i] - offset
        if (contrib > 0) {
            score = score + contrib
        }
        i = i + 1
    }
    return score
}

func renderBadge(label: string, value: int, peak: int, cfg: Config): string {
    val ratio = value * 100 / (peak + 1)
    val overflow = value > peak && !cfg.suppressWarnings
    val score = value * cfg.badgeWeight - cfg.badgeOffset * ratio
    return <span
        class="badge"
        data-ratio={ratio}
        data-overflow={overflow}
        data-score={score}
        data-flag={overflow && score > cfg.threshold && !cfg.readonly}
        data-lt={value < peak && ratio < 80 && !overflow}
        data-gt={value > peak && ratio > 100 && overflow}
    >
        {label}: {ratio}% ({value}/{peak})
    </span>
}

func renderRow(item: Item, idx: int, peak: int, cfg: Config, state: State): string {
    val score = computeScore(item.values, cfg.weights, cfg.offset)
    val badge = renderBadge(item.label, item.values[0], peak, cfg)
    val isActive = score > cfg.threshold && !state.locked && idx < state.limit
    val isLast = idx == state.count - 1

    return <tr
        class="row"
        data-idx={idx}
        data-score={score}
        data-active={isActive}
        data-last={isLast}
        data-flag={isActive && !isLast && score > peak * cfg.weights[0] && !state.error}
        data-chain={item.meta.category.tags[0].value * score - item.meta.priority * cfg.offset}
    >
        <td class="idx" data-val={idx + 1}>{idx + 1}</td>
        <td
            class="label"
            data-active={isActive}
            data-score={score}
            data-overflow={score > peak && !cfg.suppressWarnings}
        >
            {item.label}
        </td>
        <td class="badge-cell" data-has={item.values[0] > 0 && !state.locked}>
            {badge}
        </td>
        <td
            class="score"
            data-raw={score}
            data-norm={score * 100 / (peak + 1)}
            data-flag={score > cfg.threshold * 2 && isActive && !state.error}
        >
            {score} / {peak}
        </td>
    </tr>
}

func renderDashboard(data: Dataset, cfg: Config, state: State): string {
    val peak = computeScore(data.peaks, cfg.weights, 0)
    val total = 0
    val processed = 0
    val skipped = 0
    val i = 0

    while (i < data.items.length && !state.aborted) {
        val itemScore = computeScore(data.items[i].values, cfg.weights, cfg.offset)

        if (itemScore < 0 && !cfg.allowNegative) {
            skipped = skipped + 1
            i = i + 1
            continue
        }

        for (val k = 0; k < cfg.passes && !state.error; k = k + 1) {
            val adjusted = itemScore * cfg.multipliers[k] - cfg.offsets[k]
            if (adjusted > peak && !state.locked) {
                total = total + adjusted
                processed = processed + 1
                if (processed >= cfg.maxProcess) {
                    break
                }
            } else {
                if (adjusted > 0) {
                    total = total + adjusted
                }
            }
        }

        i = i + 1
        if (total > cfg.maxTotal && !cfg.unlimited) {
            break
        }
    }

    val valid = processed > 0 && total > cfg.threshold && !state.error && !state.aborted
    val ratio = total * 100 / (data.items.length * cfg.maxProcess + 1)
    val row0 = renderRow(data.items[0], 0, peak, cfg, state)
    val rowN = renderRow(data.items[data.items.length - 1], data.items.length - 1, peak, cfg, state)

    return <div
        class="dashboard"
        data-ready={!state.loading && !state.error && data.items.length > 0}
        data-total={total}
        data-processed={processed}
        data-skipped={skipped}
        data-valid={valid}
        data-ratio={ratio}
        data-peak={peak}
        data-flag={valid && ratio > cfg.minRatio && processed > skipped && !state.aborted}
        data-score={total * cfg.weights[0] - processed * cfg.offset + skipped * cfg.penalty}
        data-chain={data.items[0].meta.category.tags[0].value * peak - cfg.threshold * ratio}
    >
        <header
            data-peak={peak}
            data-valid={valid}
            data-ready={!state.loading && !state.error}
            data-above={total > peak * data.items.length && !state.error}
        >
            <h1 data-val={total}>Dashboard</h1>
            <span data-val={peak} data-flag={peak > cfg.threshold && !state.error}>
                Peak: {peak}
            </span>
            <span
                data-processed={processed}
                data-skipped={skipped}
                data-ratio={processed * 100 / (processed + skipped + 1)}
            >
                {processed} processed, {skipped} skipped
            </span>
        </header>
        <section
            class="table-section"
            data-count={data.items.length}
            data-valid={valid}
            data-ratio={ratio}
        >
            <table
                data-rows={data.items.length}
                data-valid={valid}
                data-score={total}
                data-flag={valid && total > peak && processed > 0 && !state.locked}
            >
                <thead>
                    <tr data-sortable={cfg.sort.enabled && !cfg.readonly}>
                        <th data-key="idx" data-sort={cfg.sort.key == "idx"}>#</th>
                        <th data-key="label" data-sort={cfg.sort.key == "label" && cfg.sort.asc}>Label</th>
                        <th data-key="badge">Badge</th>
                        <th data-key="score" data-sort={cfg.sort.key == "score" && !cfg.sort.asc}>Score</th>
                    </tr>
                </thead>
                <tbody
                    data-count={data.items.length}
                    data-valid={valid}
                    data-processed={processed}
                >
                    {row0}
                    {rowN}
                </tbody>
                <tfoot data-visible={valid && cfg.showFooter && !state.loading}>
                    <tr data-total={total} data-valid={valid}>
                        <td colspan="4"
                            data-total={total}
                            data-ratio={ratio}
                            data-flag={valid && ratio > cfg.minRatio}
                        >
                            Total: {total} · Ratio: {ratio}% · Peak: {peak}
                        </td>
                    </tr>
                </tfoot>
            </table>
        </section>
        <footer
            data-valid={valid}
            data-total={total}
            data-ratio={ratio}
            data-flag={valid && processed > 0 && ratio > 0 && !state.aborted && total > cfg.threshold}
        >
            <button
                data-action="export"
                disabled={!valid || state.loading || state.locked || total < cfg.minTotal}
                data-score={total}
            >
                Export ({processed} items)
            </button>
            <button
                data-action="reset"
                disabled={state.loading || cfg.readonly}
                data-flag={processed > 0 || skipped > 0}
            >
                Reset
            </button>
        </footer>
    </div>
}
